#!/usr/bin/env node
/**
 * ForgeCAD Bench Runner
 *
 * Runs a functional test harness against a solution — either a local file
 * or one generated by an LLM via OpenRouter.
 *
 * Usage:
 *   # Test a local solution file
 *   node bench/runner.js --task examples/bench/simple-tongs --solution path/to/solution.forge.js
 *
 *   # Generate + test via LLM (OpenRouter)
 *   node bench/runner.js --task examples/bench/simple-tongs --model minimax/minimax-m2.7
 *
 *   # Run all tasks against an LLM
 *   node bench/runner.js --all --model minimax/minimax-m2.7
 *
 * Environment:
 *   OPENROUTER_API_KEY — required for --model mode
 */

import { readFileSync, writeFileSync, copyFileSync, unlinkSync, existsSync, readdirSync } from "fs";
import { execSync } from "child_process";
import { join, resolve, basename } from "path";

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

const args = process.argv.slice(2);
function getArg(name) {
  const idx = args.indexOf(`--${name}`);
  if (idx === -1) return null;
  return args[idx + 1] || null;
}
const hasFlag = (name) => args.includes(`--${name}`);

const taskDir = getArg("task");
const solutionPath = getArg("solution");
const modelId = getArg("model");
const runAll = hasFlag("all");
const parallel = hasFlag("parallel");
const verbose = hasFlag("verbose");
const apiKey = process.env.OPENROUTER_API_KEY || getArg("api-key");

if (!runAll && !taskDir) {
  console.error("Usage: node bench/runner.js --task <task-dir> [--solution <file> | --model <model-id>]");
  console.error("       node bench/runner.js --all --model <model-id>");
  process.exit(1);
}

if (modelId && !apiKey) {
  console.error("Error: OPENROUTER_API_KEY env var or --api-key required for LLM mode");
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Discover tasks
// ---------------------------------------------------------------------------

const benchRoot = resolve("examples/bench");

function discoverTasks() {
  const dirs = readdirSync(benchRoot, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => join(benchRoot, d.name))
    .filter((d) => existsSync(join(d, "harness.forge.js")) && existsSync(join(d, "prompt.md")));
  return dirs;
}

// ---------------------------------------------------------------------------
// LLM generation via OpenRouter
// ---------------------------------------------------------------------------

async function generateSolution(task, model) {
  const prompt = readFileSync(join(task, "prompt.md"), "utf8");
  const apiRef = existsSync(join(benchRoot, "api-reference.md"))
    ? readFileSync(join(benchRoot, "api-reference.md"), "utf8")
    : "";

  const systemPrompt = `You are a CAD engineer writing ForgeCAD scripts. ForgeCAD uses JavaScript with a globally available API (no imports needed). Scripts must return geometry via a \`return\` statement.

${apiRef}

IMPORTANT RULES:
- Return ONLY the JavaScript code — no markdown fences, no explanation
- The script must end with a \`return\` statement
- All API functions are global (no imports)
- Coordinate system: Z-up, millimeters, degrees`;

  const userPrompt = `${prompt}

Write the ForgeCAD script. Return ONLY the JavaScript code, nothing else.`;

  if (verbose) console.log(`  Calling ${model}...`);

  const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      model,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt },
      ],
      temperature: 0.3,
      max_tokens: 4096,
    }),
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`OpenRouter API error ${response.status}: ${text}`);
  }

  const data = await response.json();
  let code = data.choices?.[0]?.message?.content || "";

  // Strip markdown fences if the model wrapped the code
  // Try to extract code from ```...``` block first
  const fenceMatch = code.match(/```(?:javascript|js)?\s*\n([\s\S]*?)```/);
  if (fenceMatch) {
    code = fenceMatch[1].trim();
  } else {
    // Fallback: strip any leading/trailing fences
    code = code.replace(/^```(?:javascript|js)?\s*\n?/gm, "").replace(/\n?```\s*$/gm, "").trim();
  }

  if (verbose) {
    console.log(`  Generated ${code.length} chars`);
    console.log(`  Tokens: ${data.usage?.total_tokens || "?"}`);
    if (code.length === 0) {
      console.log(`  Raw response (first 500 chars): ${(data.choices?.[0]?.message?.content || "").slice(0, 500)}`);
    }
  }

  return code;
}

// ---------------------------------------------------------------------------
// Run a harness and parse the score
// ---------------------------------------------------------------------------

function runHarness(task) {
  const harness = join(task, "harness.forge.js");

  try {
    const output = execSync(`forgecad run "${harness}" 2>&1`, {
      encoding: "utf8",
      timeout: 30000,
      cwd: process.cwd(),
    });

    // Parse score from output: "SCORE: 8/10 (80%)"
    const scoreMatch = output.match(/SCORE:\s*(\d+)\/(\d+)\s*\((\d+)%\)/);
    const passed = scoreMatch ? parseInt(scoreMatch[1]) : 0;
    const total = scoreMatch ? parseInt(scoreMatch[2]) : 0;
    const pct = scoreMatch ? parseInt(scoreMatch[3]) : 0;

    // Extract individual test results
    const tests = [];
    const testLines = output.match(/║\s+[✓✗]\s+T\d+:.*/g) || [];
    for (const line of testLines) {
      const pass = line.includes("✓");
      const name = line.replace(/║\s+[✓✗]\s+/, "").replace(/ — .*/, "").trim();
      const failMsg = line.includes(" — ") ? line.split(" — ").slice(1).join(" — ").trim() : null;
      tests.push({ name, pass, failMsg });
    }

    return { passed, total, pct, tests, output, error: null };
  } catch (e) {
    // Script crashed — extract error
    const output = e.stdout || e.stderr || e.message;
    const errorMatch = output.match(/ERROR:\s*(.*?)(?:\n|$)/);
    return {
      passed: 0,
      total: 0,
      pct: 0,
      tests: [],
      output,
      error: errorMatch ? errorMatch[1] : "Script crashed",
    };
  }
}

// ---------------------------------------------------------------------------
// Run a single task
// ---------------------------------------------------------------------------

async function runTask(task, model, solution) {
  const taskName = basename(task);
  const solutionFile = join(task, "solution.forge.js");
  let generated = false;

  try {
    // Place solution file
    if (solution) {
      copyFileSync(solution, solutionFile);
    } else if (model) {
      const code = await generateSolution(task, model);
      writeFileSync(solutionFile, code, "utf8");
      generated = true;
    } else {
      console.error(`  No solution or model specified for ${taskName}`);
      return null;
    }

    // Run harness
    const result = runHarness(task);
    result.taskName = taskName;
    result.model = model || "local";

    if (verbose || !runAll) {
      // Print the scorecard from the harness output
      const scoreLines = (result.output || "").split("\n").filter((l) => l.includes("[warn]"));
      for (const line of scoreLines) {
        console.log(line.replace(/.*\[warn\]\s*/, "  "));
      }
    }

    return result;
  } finally {
    // Save generated solution for debugging, clean up otherwise
    if (generated && existsSync(solutionFile)) {
      const debugPath = join(task, `solution-${(model || "unknown").replace(/\//g, "_")}.forge.js`);
      copyFileSync(solutionFile, debugPath);
      unlinkSync(solutionFile);
      if (verbose) console.log(`  Saved to ${debugPath}`);
    }
  }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main() {
  const tasks = runAll ? discoverTasks() : [resolve(taskDir)];

  if (tasks.length === 0) {
    console.error("No benchmark tasks found");
    process.exit(1);
  }

  console.log(`\nForgeCAD Bench — ${modelId || "local solution"}`);
  console.log(`Tasks: ${tasks.map((t) => basename(t)).join(", ")}\n`);

  let allResults = [];

  if (parallel && modelId) {
    // Parallel mode: generate all solutions concurrently, then run harnesses
    console.log(`  (parallel mode — generating all solutions concurrently)\n`);
    const promises = tasks.map(async (task) => {
      const taskName = basename(task);
      try {
        const result = await runTask(task, modelId, solutionPath);
        return result;
      } catch (e) {
        return { taskName, passed: 0, total: 0, pct: 0, tests: [], output: "", error: e.message };
      }
    });
    const settled = await Promise.all(promises);
    for (const result of settled) {
      if (result) {
        allResults.push(result);
        const name = result.taskName || "?";
        console.log(`─── ${name} ───`);
        if (result.error) {
          console.log(`  ERROR: ${result.error}\n`);
        } else {
          console.log(`  Score: ${result.passed}/${result.total} (${result.pct}%)\n`);
        }
      }
    }
  } else {
    // Sequential mode
    for (const task of tasks) {
      const taskName = basename(task);
      console.log(`─── ${taskName} ───`);

      const result = await runTask(task, modelId, solutionPath);
      if (result) {
        allResults.push(result);
        if (result.error) {
          console.log(`  ERROR: ${result.error}\n`);
        } else {
          console.log(`  Score: ${result.passed}/${result.total} (${result.pct}%)\n`);
        }
      }
    }
  }

  // Summary table
  if (allResults.length > 1) {
    console.log("═══════════════════════════════════════════");
    console.log("  BENCHMARK SUMMARY");
    console.log("───────────────────────────────────────────");
    let totalPassed = 0;
    let totalTests = 0;
    for (const r of allResults) {
      const status = r.error ? `ERROR: ${r.error}` : `${r.passed}/${r.total} (${r.pct}%)`;
      console.log(`  ${r.taskName.padEnd(22)} ${status}`);
      totalPassed += r.passed;
      totalTests += r.total;
    }
    console.log("───────────────────────────────────────────");
    const totalPct = totalTests > 0 ? Math.round((100 * totalPassed) / totalTests) : 0;
    console.log(`  ${"TOTAL".padEnd(22)} ${totalPassed}/${totalTests} (${totalPct}%)`);
    console.log("═══════════════════════════════════════════");
  }
}

main().catch((e) => {
  console.error("Fatal:", e.message);
  process.exit(1);
});
